parameters.jsCode:
const request = $('Execute Workflow Trigger').first().json;
let parsed;
try {
  const content = $json.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch {
  parsed = null;
}
const hashtags = Array.isArray(parsed?.hashtags) ? parsed.hashtags.filter(Boolean).slice(0, 8) : [];
const valid = Boolean(parsed && (parsed.caption || parsed.hook));
const fallback = request.page.language === 'th'
  ? { hook: `โพสต์ใหม่จาก ${request.page.page_name}`, caption: `ภาพนี้เกี่ยวกับ ${request.page.page_niche} พร้อมเล่าเรื่องจากไฟล์ ${request.image.file_name}`, cta: 'ติดตามโพสต์ถัดไปได้เลย', hashtags: ['#อัปเดตใหม่', '#โพสต์อัตโนมัติ'], confidence: 0.35 }
  : { hook: `Fresh post from ${request.page.page_name}`, caption: `This image highlights ${request.page.page_niche} based on ${request.image.file_name}.`, cta: 'Follow for the next update.', hashtags: ['#newpost', '#automation'], confidence: 0.35 };
const payload = valid ? parsed : fallback;
payload.hashtags = Array.isArray(payload.hashtags) ? payload.hashtags : [];
payload.confidence = Number.isFinite(Number(payload.confidence)) ? Math.max(0, Math.min(1, Number(payload.confidence))) : 0.35;
payload.final_caption_text = [payload.hook, payload.caption, payload.cta, payload.hashtags.join(' ')].filter(Boolean).join('\n\n').slice(0, 2200);
return [{ json: { ...request, ai_valid: valid, caption_payload: payload, ai_raw: $json } }];
